code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, icon } from 'decantr/components';

code.example:
function ApiKeyRow({ apiKey, onCopy, onRevoke }) {
  const { div, span } = tags;
  const masked = apiKey.key_prefix + '••••••••••••••••';

  return div({ class: css('_flex _aic _gap4 _px4 _py4 _borderb _bordermuted/10') },
    icon('key', { size: '1.25rem', class: css('_fgmuted _shrink0') }),
    div({ class: css('_flex _col _gap1 _flex1 _min-w0') },
      span({ class: css('_textsm _fontmedium') }, apiKey.name),
      span({ class: css('_textxs _mono _fgmuted _truncate') }, masked)
    ),
    div({ class: css('_flex _gap1 _shrink0') },
      ...apiKey.scopes.map(scope =>
        Badge({ variant: 'outline', size: 'xs' }, scope)
      )
    ),
    div({ class: css('_flex _col _gap1 _shrink0 _textxs _fgmuted _text-right') },
      span({}, `Created ${apiKey.created_at}`),
      span({}, apiKey.last_used_at ? `Last used ${apiKey.last_used_at}` : 'Never used')
    ),
    div({ class: css('_flex _gap2 _shrink0') },
      Button({ variant: 'ghost', size: 'sm', onclick: () => onCopy(apiKey) },
        icon('copy', { size: '0.875rem' })
      ),
      Button({ variant: 'ghost', size: 'sm', onclick: () => onRevoke(apiKey.id) },
        icon('trash', { size: '0.875rem', class: css('_fgdestructive') })
      )
    )
  );
}

